static int tycho_eq_S_Token(S_Token a, S_Token b) {
    return tycho_eq_E_Tok(a.f_kind, b.f_kind)
        && (strcmp(a.f_text, b.f_text) == 0)
        && (a.f_line == b.f_line)
        && (a.f_col == b.f_col);
}

static int tycho_eq_S_Param(S_Param a, S_Param b) {
    return (strcmp(a.f_name, b.f_name) == 0)
        && (strcmp(a.f_ty, b.f_ty) == 0);
}

static int tycho_eq_S_Func(S_Func a, S_Func b) {
    return (strcmp(a.f_name, b.f_name) == 0)
        && tycho_arr_str_eq(a.f_params, b.f_params)
        && tycho_arr_str_eq(a.f_ptypes, b.f_ptypes)
        && (strcmp(a.f_ret, b.f_ret) == 0)
        && tycho_arr_C2_eq(a.f_body, b.f_body)
        && (a.f_is_extern == b.f_is_extern)
        && (strcmp(a.f_lib, b.f_lib) == 0)
        && (strcmp(a.f_constraints, b.f_constraints) == 0);
}

static int tycho_eq_S_Sig(S_Sig a, S_Sig b) {
    return (strcmp(a.f_name, b.f_name) == 0)
        && (strcmp(a.f_ret, b.f_ret) == 0)
        && tycho_arr_str_eq(a.f_ptypes, b.f_ptypes)
        && (a.f_is_extern == b.f_is_extern);
}

static int tycho_eq_S_LamInfo(S_LamInfo a, S_LamInfo b) {
    return (a.f_id == b.f_id)
        && (strcmp(a.f_ftype, b.f_ftype) == 0)
        && tycho_arr_str_eq(a.f_capnames, b.f_capnames)
        && tycho_arr_str_eq(a.f_captypes, b.f_captypes)
        && tycho_arr_str_eq(a.f_lamptypes, b.f_lamptypes)
        && (strcmp(a.f_ret, b.f_ret) == 0);
}

