static int tycho_eq_E_Expr(E_Expr *a, E_Expr *b) {
    if (a->tag != b->tag) return 0;
    if (a->tag == 0) { return (strcmp(a->u.EInt.f0, b->u.EInt.f0) == 0) && (a->u.EInt.f1 == b->u.EInt.f1); }
    if (a->tag == 1) { return (strcmp(a->u.EBool.f0, b->u.EBool.f0) == 0) && (a->u.EBool.f1 == b->u.EBool.f1); }
    if (a->tag == 2) { return (strcmp(a->u.EChar.f0, b->u.EChar.f0) == 0) && (a->u.EChar.f1 == b->u.EChar.f1); }
    if (a->tag == 3) { return (strcmp(a->u.EFloat.f0, b->u.EFloat.f0) == 0) && (a->u.EFloat.f1 == b->u.EFloat.f1); }
    if (a->tag == 4) { return (strcmp(a->u.EStr.f0, b->u.EStr.f0) == 0) && (a->u.EStr.f1 == b->u.EStr.f1); }
    if (a->tag == 5) { return (strcmp(a->u.EVar.f0, b->u.EVar.f0) == 0) && (a->u.EVar.f1 == b->u.EVar.f1); }
    if (a->tag == 6) { return (strcmp(a->u.EBin.f0, b->u.EBin.f0) == 0) && tycho_eq_E_Expr(a->u.EBin.f1, b->u.EBin.f1) && tycho_eq_E_Expr(a->u.EBin.f2, b->u.EBin.f2) && (a->u.EBin.f3 == b->u.EBin.f3); }
    if (a->tag == 7) { return (strcmp(a->u.ECall.f0, b->u.ECall.f0) == 0) && tycho_arr_C1_eq(a->u.ECall.f1, b->u.ECall.f1) && (a->u.ECall.f2 == b->u.ECall.f2); }
    if (a->tag == 8) { return tycho_eq_E_Expr(a->u.EField.f0, b->u.EField.f0) && (strcmp(a->u.EField.f1, b->u.EField.f1) == 0) && (a->u.EField.f2 == b->u.EField.f2); }
    if (a->tag == 9) { return tycho_eq_E_Expr(a->u.EIndex.f0, b->u.EIndex.f0) && tycho_eq_E_Expr(a->u.EIndex.f1, b->u.EIndex.f1) && (a->u.EIndex.f2 == b->u.EIndex.f2); }
    if (a->tag == 10) { return tycho_arr_C1_eq(a->u.EArrLit.f0, b->u.EArrLit.f0) && (a->u.EArrLit.f1 == b->u.EArrLit.f1); }
    if (a->tag == 11) { return (strcmp(a->u.EArrEmpty.f0, b->u.EArrEmpty.f0) == 0) && (a->u.EArrEmpty.f1 == b->u.EArrEmpty.f1); }
    if (a->tag == 12) { return (strcmp(a->u.EMapEmpty.f0, b->u.EMapEmpty.f0) == 0) && (strcmp(a->u.EMapEmpty.f1, b->u.EMapEmpty.f1) == 0) && (a->u.EMapEmpty.f2 == b->u.EMapEmpty.f2); }
    if (a->tag == 13) { return tycho_arr_C1_eq(a->u.EMapLit.f0, b->u.EMapLit.f0) && tycho_arr_C1_eq(a->u.EMapLit.f1, b->u.EMapLit.f1) && (a->u.EMapLit.f2 == b->u.EMapLit.f2); }
    if (a->tag == 14) { return tycho_arr_C1_eq(a->u.ETuple.f0, b->u.ETuple.f0) && (a->u.ETuple.f1 == b->u.ETuple.f1); }
    if (a->tag == 15) { return tycho_eq_E_Expr(a->u.ESlice.f0, b->u.ESlice.f0) && tycho_eq_E_Expr(a->u.ESlice.f1, b->u.ESlice.f1) && tycho_eq_E_Expr(a->u.ESlice.f2, b->u.ESlice.f2) && (a->u.ESlice.f3 == b->u.ESlice.f3); }
    if (a->tag == 16) { return tycho_eq_E_Expr(a->u.EAddr.f0, b->u.EAddr.f0) && (a->u.EAddr.f1 == b->u.EAddr.f1); }
    if (a->tag == 17) { return (a->u.ELambda.f0 == b->u.ELambda.f0) && tycho_arr_str_eq(a->u.ELambda.f1, b->u.ELambda.f1) && tycho_arr_str_eq(a->u.ELambda.f2, b->u.ELambda.f2) && (strcmp(a->u.ELambda.f3, b->u.ELambda.f3) == 0) && tycho_eq_E_Expr(a->u.ELambda.f4, b->u.ELambda.f4) && tycho_arr_str_eq(a->u.ELambda.f5, b->u.ELambda.f5) && tycho_arr_str_eq(a->u.ELambda.f6, b->u.ELambda.f6) && (a->u.ELambda.f7 == b->u.ELambda.f7); }
    if (a->tag == 18) { return tycho_eq_E_Expr(a->u.ECallV.f0, b->u.ECallV.f0) && tycho_arr_C1_eq(a->u.ECallV.f1, b->u.ECallV.f1) && (a->u.ECallV.f2 == b->u.ECallV.f2); }
    if (a->tag == 19) { return (a->u.ESpawn.f0 == b->u.ESpawn.f0) && (strcmp(a->u.ESpawn.f1, b->u.ESpawn.f1) == 0) && tycho_arr_C1_eq(a->u.ESpawn.f2, b->u.ESpawn.f2) && (a->u.ESpawn.f3 == b->u.ESpawn.f3); }
    return 1;
}

